const raw = $input.first().json;

let data = raw.body ?? raw;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch(e) { throw new Error('Invalid JSON body: ' + e.message); }
}

let body = data.test_cases ? data.test_cases[0].body : data;
if (typeof body === 'string') {
  try { body = JSON.parse(body); } catch(e) {}
}

if (!body.student_id)       throw new Error('Missing: student_id');
if (!body.mastery_profile)  throw new Error('Missing: mastery_profile');
if (!Array.isArray(body.mastery_profile.knowledge_gaps)) throw new Error('knowledge_gaps must be an array');
if (body.mastery_profile.knowledge_gaps.length === 0)    throw new Error('No knowledge gaps found');

return [{
  json: {
    student_id:            String(body.student_id),
    analysis_timestamp:    body.analysis_timestamp || new Date().toISOString(),
    overall_mastery_score: body.mastery_profile.overall_mastery_score ?? null,
    knowledge_gaps:        body.mastery_profile.knowledge_gaps,
    strengths:             body.mastery_profile.strengths    || [],
    recommendations:       body.recommendations              || {},
    data_sources:          body.data_sources                 || {}
  }
}];

const data = $input.first().json;

const DIFFICULTY_MAP = {
  'FUNDAMENTAL_GAP': 'beginner',
  'PARTIAL_GAP':     'intermediate',
  'SURFACE_GAP':     'intermediate'
};
const CONTENT_TYPE_MAP = {
  'interactive_tutorial':  ['concept_explanation','step_by_step_tutorial','coding_examples'],
  'step_by_step_practice': ['step_by_step_tutorial','debugging_task','practice_exercises'],
  'targeted_quiz':         ['concept_summary','quiz','practice_exercises'],
  'practice_exercises':    ['practice_exercises','coding_examples','quiz']
};

const studentId    = String(data.student_id);
const masteryScore = data.overall_mastery_score ?? null;

const processedGaps = data.knowledge_gaps.map((gap, index) => {
  const intervention        = gap.suggested_intervention || {};
  const primaryIntervention = intervention.primary || 'interactive_tutorial';
  const contentTypes        = CONTENT_TYPE_MAP[primaryIntervention] || ['concept_explanation','practice_exercises'];
  return {
    student_id:            studentId,
    overall_mastery_score: masteryScore,
    priority:              index + 1,
    topic:                 gap.topic,
    topic_id:              gap.topic_id,
    gap_type:              gap.gap_type,
    difficulty_level:      DIFFICULTY_MAP[gap.gap_type] || intervention.difficulty_level || 'beginner',
    misconceptions:        gap.misconceptions           || [],
    error_patterns:        gap.observed_error_patterns  || {},
    evidence_summary:      gap.evidence_summary         || '',
    prerequisite_topics:   gap.prerequisite_topics      || [],
    related_topics:        gap.related_topics           || [],
    learning_objectives:   intervention.learning_objectives || [],
    content_types_to_generate: contentTypes,
    estimated_time_minutes: intervention.estimated_time_minutes || 60,
    primary_intervention:  primaryIntervention
  };
});

return [{
  json: {
    student_id:            studentId,
    analysis_timestamp:    data.analysis_timestamp,
    overall_mastery_score: masteryScore,
    strengths:             data.strengths,
    processed_gaps:        processedGaps,
    recommendations:       data.recommendations,
    processing_timestamp:  new Date().toISOString()
  }
}];

const item = $json;
const gap  = item.gap || item;

const studentId    = gap.student_id    || item.student_id    || 'UNKNOWN';
const masteryScore = gap.overall_mastery_score ?? item.overall_mastery_score ?? 'N/A';
const topic        = gap.topic        || 'Unknown Topic';
const level        = gap.difficulty_level || 'beginner';
const gapType      = gap.gap_type     || 'FUNDAMENTAL_GAP';

const misconceptions = (gap.misconceptions || []).slice(0, 3).map((m, i) => `${i+1}. ${m}`).join('\n') || 'None listed';
const prereqs        = (gap.prerequisite_topics || []).slice(0, 3).join(', ') || 'None';
const relatedTopics  = (gap.related_topics || []).slice(0, 2).join(', ')      || 'advanced topics';
const objectives     = (gap.learning_objectives || []).slice(0, 3).map((o, i) => `${i+1}. ${o}`).join('\n') || 'Master the concept';
const evidence       = (gap.evidence_summary || 'No evidence provided').substring(0, 200);

// USER PROMPT: student context only — JSON schema is in the system prompt
const llmPrompt = `STUDENT: ${studentId} | Score: ${masteryScore}/100 | Level: ${level}
TOPIC: ${topic} (${gapType})
KNOWS: ${prereqs}
UNLOCKS: ${relatedTopics}
MISCONCEPTIONS:
${misconceptions}
EVIDENCE: ${evidence}
OBJECTIVES:
${objectives}`;

const slmPrompt = `STUDENT: ${studentId} | Topic: ${topic} | Level: ${level}
MISCONCEPTIONS:
${misconceptions}
EVIDENCE: ${evidence}`;

return [{
  json: {
    ...item,
    student_id:            studentId,
    overall_mastery_score: masteryScore,
    gap:                   gap,
    llm_prompt:            llmPrompt,
    slm_prompt:            slmPrompt,
    prompt_generated_at:   new Date().toISOString(),
    agent_retry_count:     0,
    agent_state:           'initial'
  }
}];

const item     = $input.first().json;
const upstream = $('Prompt Construction Module').first().json;

const raw = (item.message?.content || item.response || '').trim();

function stripFences(s) {
  return s.replace(/^```json\s*/gi, '').replace(/^```\s*/gi, '').replace(/\s*```$/gi, '').replace(/^`+/g, '').replace(/`+$/g, '').trim();
}

function findOutermostObject(s) {
  const start = s.indexOf('{');
  if (start === -1) return null;
  let depth = 0;
  for (let i = start; i < s.length; i++) {
    if (s[i] === '{') depth++;
    else if (s[i] === '}') { depth--; if (depth === 0) return s.substring(start, i + 1); }
  }
  const lastClose = s.lastIndexOf('}');
  if (lastClose > start) return s.substring(start, lastClose + 1);
  return null;
}

function extractField(s, fieldName, type) {
  if (type === 'string') {
    const re = new RegExp('"' + fieldName + '"\\s*:\\s*"((?:[^"\\\\]|\\\\.)*)"', 's');
    const m = s.match(re);
    return m ? m[1].replace(/\\n/g,'\n').replace(/\\"/g,'"') : null;
  }
  const bracket = type === 'array' ? '[' : '{';
  const closeBracket = type === 'array' ? ']' : '}';
  const re = new RegExp('"' + fieldName + '"\\s*:\\s*(\\' + bracket + ')');
  const m = re.exec(s);
  if (!m) return null;
  let start = m.index + m[0].length - 1;
  let depth = 0;
  for (let i = start; i < s.length; i++) {
    if (s[i] === bracket) depth++;
    else if (s[i] === closeBracket) { depth--; if (depth === 0) { try { return JSON.parse(s.substring(start, i+1)); } catch(e) { return null; } } }
  }
  return null;
}

let llmContent = null;
let parseError  = null;
const cleaned   = stripFences(raw);
const candidate = findOutermostObject(cleaned);

if (candidate) {
  try {
    llmContent = JSON.parse(candidate);
  } catch(e) {
    parseError = 'JSON.parse failed: ' + e.message;
    const partial = {};
    ['page_title'].forEach(f => { partial[f] = extractField(candidate, f, 'string'); });
    ['introduction','concept_explained','syntax_reference','examples','step_by_step_guide','debugging_exercise','quick_reference','connections'].forEach(f => { partial[f] = extractField(candidate, f, 'object'); });
    ['common_mistakes'].forEach(f => { partial[f] = extractField(candidate, f, 'array'); });
    const filledCount = Object.values(partial).filter(v => v !== null).length;
    if (filledCount > 0) {
      partial._extraction_method = 'field_by_field_fallback';
      partial._fields_recovered  = filledCount;
      llmContent = partial;
      parseError += ` | fallback recovered ${filledCount} fields`;
    } else {
      llmContent = { parse_failed: true, raw_response: raw.substring(0, 3000), error: parseError };
    }
  }
} else {
  parseError = 'No JSON object found';
  llmContent  = { parse_failed: true, raw_response: raw.substring(0, 3000), error: parseError };
}

return [{
  json: {
    student_id:            upstream.student_id,
    gap:                   upstream.gap,
    overall_mastery_score: upstream.overall_mastery_score,
    llm_output:            llmContent,
    llm_parse_error:       parseError,
    llm_model:             'qwen2.5-coder:7b',
    llm_responded_at:      new Date().toISOString(),
    agent_retry_count:     upstream.agent_retry_count || 0,
    agent_state:           upstream.agent_state || 'initial',
    llm_prompt:            upstream.llm_prompt,
    slm_prompt:            upstream.slm_prompt
  }
}];

// ── QUALITY REVIEW AGENT V19 ─────────────────────────────────────────
// Fixed: lower threshold (60 not 80) for 7b model, MAX_RETRIES=1 to
// prevent 6-minute timeout loops. Patch fills gaps intelligently.

const item = $input.first().json;
const llm  = item.llm_output || {};
const gap  = item.gap || {};
const retryCount = item.agent_retry_count || 0;
const MAX_RETRIES = 1; // was 2 — one retry is enough for a 7b model

// ── Quality scoring ───────────────────────────────────────────────────
const checks = {
  has_title:          !!llm.page_title,
  has_introduction:   !!(llm.introduction?.what_is_it),
  has_concept:        !!(llm.concept_explained?.core_definition),
  has_syntax:         !!(llm.syntax_reference?.basic_syntax),
  has_examples:       !!(llm.examples?.example_1?.code),
  has_steps:          Array.isArray(llm.step_by_step_guide?.steps) && llm.step_by_step_guide.steps.length >= 3,
  has_debug_exercise: !!(llm.debugging_exercise?.broken_code),
  has_mistakes:       Array.isArray(llm.common_mistakes) && llm.common_mistakes.length >= 2,
  no_parse_fail:      !llm.parse_failed,
  no_empty_codes:     !!(llm.examples?.example_1?.code?.length > 20)
};

const passedChecks = Object.values(checks).filter(Boolean).length;
const totalChecks  = Object.keys(checks).length;
const qualityScore = Math.round((passedChecks / totalChecks) * 100);

// ── Agent Decision — threshold lowered to 60 for 7b model ────────────
let agentDecision;
let refinedPromptAddition = '';

// CRITICAL FIX: if LLM returned nothing (parse_failed + empty), go straight
// to patch after 1 retry — retrying a timed-out model wastes 6 minutes
const isCompletelyEmpty = llm.parse_failed && retryCount >= MAX_RETRIES;
const isEmptyFirstPass  = llm.parse_failed && retryCount === 0;

if (qualityScore >= 60 && !llm.parse_failed) {
  agentDecision = 'ACCEPT';
} else if (isCompletelyEmpty || retryCount >= MAX_RETRIES) {
  agentDecision = 'ACCEPT_WITH_PATCH';
} else {
  agentDecision = 'RETRY';
  const missing = Object.entries(checks).filter(([k,v]) => !v).map(([k]) => k);
  refinedPromptAddition = `

⚠ RETRY ${retryCount + 1}: Missing sections: ${missing.join(', ')}. Quality was ${qualityScore}/100. Include ALL sections with real Java content.`;
}

// ── Patch missing fields with topic-aware defaults ────────────────────
if (agentDecision === 'ACCEPT_WITH_PATCH') {
  const topic = gap.topic || 'Java Concept';
  const level = gap.difficulty_level || 'beginner';
  const prereqs = (gap.prerequisite_topics || []).join(', ') || 'basic Java';
  const related = (gap.related_topics || []).join(', ') || 'advanced Java topics';
  const misconceptions = (gap.misconceptions || []);

  if (!llm.page_title)
    llm.page_title = `Java ${topic} - MENTORA Tutorial`;

  if (!llm.introduction)
    llm.introduction = {
      what_is_it: `${topic} is a core Java concept that allows programs to ${topic.includes('OOP') || topic.includes('Polymorphism') ? 'treat objects of different types through a common interface, enabling flexible and extensible code' : topic.includes('Linked') ? 'store elements in nodes connected by references, enabling efficient insertion and deletion' : topic.includes('Exception') ? 'handle runtime errors gracefully without crashing the program' : 'organize and structure code more effectively'}. It is fundamental to writing professional Java applications.`,
      why_learn_it: `Mastering ${topic} enables you to write cleaner, more maintainable Java code. It is required knowledge for ${level === 'beginner' ? 'intermediate Java programming and most real-world projects' : 'advanced topics and professional development'}. Without understanding ${topic}, you will struggle with ${related}.`,
      prerequisite_note: `You should be comfortable with ${prereqs} before studying ${topic}.`
    };

  if (!llm.concept_explained)
    llm.concept_explained = {
      core_definition: `${topic} in Java enables ${topic.includes('OOP') || topic.includes('Polymorphism') ? 'objects of different classes to be treated as instances of a common superclass, with methods resolved at runtime' : topic.includes('Linked') ? 'a sequence of nodes where each node holds data and a reference to the next node' : topic.includes('Exception') ? 'the program to detect, signal, and recover from error conditions using try-catch-finally blocks' : 'structured, reusable programming patterns'}.`,
      analogy: `Think of ${topic} like ${topic.includes('OOP') || topic.includes('Polymorphism') ? 'a TV remote — you press "volume up" and it works whether you have a Samsung, LG, or Sony TV. The same button (method call) produces the right action depending on which TV (object type) you point it at' : topic.includes('Linked') ? 'a train — each carriage (node) is connected to the next one. To reach carriage 5, you walk through carriages 1, 2, 3, 4. Adding a new carriage only requires connecting it to its neighbours' : topic.includes('Exception') ? 'a safety net under a tightrope walker — you hope it is never needed, but when something goes wrong, it catches you and lets you recover gracefully instead of crashing to the floor' : 'a blueprint for a building — the plan defines the structure and behaviour, and you can build many instances from one plan'}.`,
      how_java_handles_it: `Java implements ${topic} through ${topic.includes('OOP') || topic.includes('Polymorphism') ? 'dynamic dispatch: when you call a method on a superclass reference, Java looks up the actual object type at runtime and calls the correct overridden method. This is enabled by the JVM's virtual method table (vtable)' : topic.includes('Linked') ? 'the LinkedList class in java.util, or custom Node classes. Each Node holds a data field and a next reference. Java's garbage collector automatically frees nodes when they are no longer referenced' : topic.includes('Exception') ? 'a hierarchy of Throwable classes. Checked exceptions (IOException, SQLException) must be declared or caught. Unchecked exceptions (NullPointerException, ArrayIndexOutOfBoundsException) extend RuntimeException and do not require explicit handling' : 'built-in language features and standard library classes'}.`,
      misconceptions_corrected: misconceptions.length > 0
        ? misconceptions.map((m, i) => `MISCONCEPTION ${i+1}: ${m}
THE TRUTH: ${topic.includes('OOP') || topic.includes('Polymorphism') ? (i===0 ? 'Overloading = same method name, different parameters (compile-time). Overriding = same signature in subclass (runtime). They are completely different mechanisms.' : i===1 ? 'Dynamic dispatch means Java decides WHICH method to call based on the actual object type at runtime, not the declared variable type. Animal a = new Dog(); a.speak() calls Dog.speak().' : 'Abstract classes can have state and concrete methods; they use extends. Interfaces define contracts; they use implements. Use abstract class for shared behaviour, interface for capability contracts.') : (i===0 ? 'Review the Java documentation and practice with small examples to correct this understanding.' : 'Practice more examples to solidify the correct mental model.')}`)
          .join('

')
        : `Common misconceptions about ${topic} can be corrected through careful study of the examples below.`
    };

  if (!llm.syntax_reference)
    llm.syntax_reference = {
      basic_syntax: topic.includes('OOP') || topic.includes('Polymorphism')
        ? `class Animal { void speak() { System.out.println("..."); } }
class Dog extends Animal { @Override void speak() { System.out.println("Woof!"); } }
Animal a = new Dog(); a.speak(); // prints: Woof! (dynamic dispatch)`
        : topic.includes('Linked')
        ? `class Node { int data; Node next; Node(int d) { data = d; next = null; } }
Node head = new Node(1);
head.next = new Node(2);
head.next.next = new Node(3);`
        : topic.includes('Exception')
        ? `try {
    // risky code
} catch (IOException e) {
    // handle checked exception
} catch (RuntimeException e) {
    // handle unchecked exception
} finally {
    // always runs
}`
        : `// Core ${topic} syntax — see examples below`,
      syntax_breakdown: `1. Declaration: defines the structure
2. Initialization: creates the instance
3. Usage: applies the concept
4. Clean-up: releases resources if needed`,
      important_rules: `1. Always define proper termination/base conditions
2. Ensure every code path returns a value
3. Handle edge cases (null, empty, boundary values)`
    };

  if (!llm.examples || !llm.examples.example_1)
    llm.examples = {
      example_1: {
        title: `Basic ${topic}`,
        description: `Demonstrates the core ${topic} concept in Java.`,
        code: topic.includes('OOP') || topic.includes('Polymorphism')
          ? `public class PolymorphismDemo {
    // Base class
    static class Animal {
        String name;
        Animal(String name) { this.name = name; }
        void speak() { System.out.println(name + " makes a sound"); }
    }
    // Subclass overrides speak()
    static class Dog extends Animal {
        Dog(String name) { super(name); }
        @Override
        void speak() { System.out.println(name + " says: Woof!"); }
    }
    static class Cat extends Animal {
        Cat(String name) { super(name); }
        @Override
        void speak() { System.out.println(name + " says: Meow!"); }
    }
    public static void main(String[] args) {
        // Polymorphic array — Animal references hold Dog and Cat objects
        Animal[] animals = { new Dog("Rex"), new Cat("Luna"), new Dog("Buddy") };
        for (Animal a : animals) {
            a.speak(); // Java calls the correct overridden method at runtime
        }
    }
}`
          : topic.includes('Linked')
          ? `public class LinkedListDemo {
    static class Node {
        int data;
        Node next;
        Node(int data) { this.data = data; this.next = null; }
    }
    static class LinkedList {
        Node head;
        void add(int data) {
            Node newNode = new Node(data);
            if (head == null) { head = newNode; return; }
            Node curr = head;
            while (curr.next != null) curr = curr.next;
            curr.next = newNode;
        }
        void print() {
            Node curr = head;
            while (curr != null) {
                System.out.print(curr.data + (curr.next != null ? " -> " : "\n"));
                curr = curr.next;
            }
        }
    }
    public static void main(String[] args) {
        LinkedList list = new LinkedList();
        list.add(10); list.add(20); list.add(30);
        list.print();
    }
}`
          : `public class ${topic.replace(/[^a-zA-Z]/g,'')}Demo {
    public static void main(String[] args) {
        System.out.println("Demonstrating ${topic}");
        example();
    }
    static void example() {
        System.out.println("Core concept applied");
        System.out.println("Study the concept_explained section above");
