        output: topic.includes('OOP') || topic.includes('Polymorphism')
          ? `Circle area: 78.54
Rectangle area: 24.00` : `Real-world application of ${topic}
Processing: 42
Result: 84`,
        explanation: `In real applications, ${topic} allows you to write code that works with multiple types through a common interface. This is the foundation of frameworks like Spring and Android.`
      },
      example_3_misconception_fix: {
        title: `Common Mistake: Fixed`,
        description: misconceptions[0] || `A common misunderstanding of ${topic}`,
        wrong_code: topic.includes('OOP') || topic.includes('Polymorphism')
          ? `public class WrongOOP {
    static class Animal {
