    };

  if (!Array.isArray(llm.common_mistakes) || llm.common_mistakes.length < 2)
    llm.common_mistakes = [
      {
        mistake_number: 1,
        title: misconceptions[0] ? misconceptions[0].substring(0, 50) : `Misusing ${topic}`,
        description: misconceptions[0] ? `Students often ${misconceptions[0].toLowerCase()}.` : `A common misunderstanding of ${topic} fundamentals.`,
        bad_code: `// BUG: Incorrect ${topic} usage
public class Mistake1 {
    public static void main(String[] args) {
        // This represents the mistake — see explanation below
        System.out.println("Wrong approach");
    }
}`,
        good_code: `// FIXED: Correct ${topic} usage
